// Build the weekly Trust Score email.

const score    = $input.first().json;
const charity  = $('Loop Over Charities').item.json;

const currentScore = score.total_score   || 0;
const prevScore    = charity.prev_score  || null;
const delta        = prevScore !== null ? currentScore - prevScore : null;

const improvements = (() => {
  try {
    const raw = score.improvements;
    if (Array.isArray(raw)) return raw;
    if (typeof raw === 'string') return JSON.parse(raw);
    return [];
  } catch { return []; }
})();

// Score colour
const scoreColor =
  currentScore >= 70 ? '#0F4C35' :
  currentScore >= 40 ? '#B45309' :
  '#991B1B';

const scoreLabel =
  currentScore >= 70 ? 'Strong' :
  currentScore >= 40 ? 'Building' :
  'Needs attention';

// Delta badge
const deltaBadge = (() => {
  if (delta === null) return '';
  if (delta > 0)  return `<span style="color:#059669;font-size:14px">▲ +${delta} pts this week</span>`;
  if (delta < 0)  return `<span style="color:#DC2626;font-size:14px">▼ ${delta} pts this week</span>`;
  return `<span style="color:#6B7280;font-size:14px">No change this week</span>`;
})();

// Sub-score bars
const subScores = [
  { label: 'Governance',   value: score.governance_score   || 0, max: 30 },
  { label: 'Financial',    value: score.financial_score    || 0, max: 20 },
  { label: 'Documents',    value: score.document_score     || 0, max: 20 },
  { label: 'Track Record', value: score.track_record_score || 0, max: 20 },
  { label: 'Applications', value: score.application_score  || 0, max: 10 }
];

const barRows = subScores.map(s => {
  const pct = s.max > 0 ? Math.round((s.value / s.max) * 100) : 0;
  return `
    <tr>
      <td style="padding:6px 0;font-size:13px;color:#374151;width:120px">${s.label}</td>
      <td style="padding:6px 8px">
        <div style="background:#e5e7eb;border-radius:4px;height:8px;overflow:hidden">
          <div style="background:${scoreColor};height:8px;width:${pct}%;border-radius:4px"></div>
        </div>
      </td>
      <td style="padding:6px 0;font-size:13px;color:#6B7280;text-align:right;white-space:nowrap">${s.value}/${s.max}</td>
    </tr>
  `;
}).join('');

const improvementsList = improvements.slice(0, 3).map(imp =>
  `<li style="color:#374151;font-size:14px;padding:6px 0;border-bottom:1px solid #f3f4f6">${imp}</li>`
).join('');

const html = `
<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="font-family:'Segoe UI',Arial,sans-serif;background:#f4f6f5;margin:0;padding:24px">
  <div style="max-width:560px;margin:0 auto;background:#ffffff;border-radius:16px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,0.06)">
    <div style="background:#0F4C35;padding:28px 36px">
      <h1 style="color:#ffffff;font-size:20px;margin:0">Your Weekly Trust Score</h1>
      <p style="color:rgba(255,255,255,0.7);font-size:14px;margin:6px 0 0">${charity.org_name}</p>
    </div>
    <div style="padding:32px 36px">
      <!-- Score ring (text-based) -->
      <div style="text-align:center;margin-bottom:28px">
        <div style="display:inline-block;background:${scoreColor};color:#ffffff;border-radius:50%;width:100px;height:100px;line-height:100px;font-size:32px;font-weight:bold;margin:0 auto">${currentScore}</div>
        <p style="color:${scoreColor};font-weight:bold;margin:10px 0 4px">${scoreLabel}</p>
        ${deltaBadge}
      </div>
      <!-- Sub-score breakdown -->
      <h3 style="color:#0D1117;font-size:15px;margin:0 0 12px">Score Breakdown</h3>
      <table style="width:100%;border-collapse:collapse;margin-bottom:24px">
        <tbody>${barRows}</tbody>
      </table>
      <!-- Improvement actions -->
      ${improvements.length > 0 ? `
        <h3 style="color:#0D1117;font-size:15px;margin:0 0 12px">Top Actions This Week</h3>
        <ul style="margin:0;padding:0;list-style:none">
          ${improvementsList}
        </ul>
      ` : '<p style="color:#059669;font-size:14px">🎉 No improvements needed — great work!</p>'}
      <div style="text-align:center;margin:28px 0">
        <a href="https://fundsradar.co/dashboard" style="display:inline-block;background:#0F4C35;color:#ffffff;font-weight:bold;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:15px">Improve My Score →</a>
      </div>
      <p style="color:#9ca3af;font-size:12px;text-align:center">Sent every Sunday · <a href="https://fundsradar.co/settings" style="color:#9ca3af">Manage preferences</a></p>
    </div>
  </div>
</body>
</html>
`;

// Skip if score is 0 (org has no data yet)
if (currentScore === 0 && improvements.length === 0) {
  console.log(`Skipping email for ${charity.org_name} — no trust score data yet`);
  return [];
}

return [{
  json: {
    to:      charity.email,
    orgName: charity.org_name,
    subject: `Your FundsRadar Trust Score this week: ${currentScore}/100`,
    html
  }
}];
